using System.ComponentModel.DataAnnotations;

namespace sv_1b806c2631d24960907d95a717b06975.Models;

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    public string Name { get; set; } = string.Empty;

    [Range(0, 9999, ErrorMessage = "Quantity must be between 0 and 9999.")]
    public int Quantity { get; set; }

    [Range(0.01, double.MaxValue, ErrorMessage = "Price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;

    public static readonly string[] Categories = { "Electronics", "Clothing", "Food", "Other" };

    public Product Clone() => new()
    {
        Id = Id,
        Name = Name,
        Quantity = Quantity,
        UnitPrice = UnitPrice,
        Category = Category
    };
}

using sv_1b806c2631d24960907d95a717b06975.Models;

namespace sv_1b806c2631d24960907d95a717b06975.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
        new Product { Id = 2, Name = "USB-C Cable", Quantity = 300, UnitPrice = 9.99m, Category = "Electronics" },
        new Product { Id = 3, Name = "Cotton T-Shirt", Quantity = 200, UnitPrice = 14.50m, Category = "Clothing" },
        new Product { Id = 4, Name = "Organic Coffee Beans", Quantity = 75, UnitPrice = 18.75m, Category = "Food" },
        new Product { Id = 5, Name = "Winter Jacket", Quantity = 40, UnitPrice = 89.99m, Category = "Clothing" },
        new Product { Id = 6, Name = "Notebook & Pen Set", Quantity = 120, UnitPrice = 7.25m, Category = "Other" }
    };

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_products.Select(p => p.Clone()).ToList());
        }
    }

    public Task<bool> UpdateAsync(Product updated)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == updated.Id);
            if (existing is null)
                return Task.FromResult(false);

            existing.Name = updated.Name;
            existing.Quantity = updated.Quantity;
            existing.UnitPrice = updated.UnitPrice;
            existing.Category = updated.Category;
            return Task.FromResult(true);
        }
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using sv_1b806c2631d24960907d95a717b06975.Models
@using sv_1b806c2631d24960907d95a717b06975.Services
@inject InventoryService InventoryService

<PageTitle>Inventory</PageTitle>

<h1>Inventory</h1>

@if (_products is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped table-bordered">
        <thead class="table-dark">
            <tr>
                <th>Name</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Category</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var product in _products)
            {
                @if (_editingProductId == product.Id && _editModel is not null)
                {
                    <tr>
                        <td>
                            <EditForm Model="_editModel" OnValidSubmit="SaveAsync" FormName="@($"edit-{product.Id}")">
                                <DataAnnotationsValidator />
                                <InputText @bind-Value="_editModel.Name" class="form-control form-control-sm" />
                                <ValidationMessage For="() => _editModel.Name" />
                        </td>
                        <td>
                                <InputNumber @bind-Value="_editModel.Quantity" class="form-control form-control-sm" />
                                <ValidationMessage For="() => _editModel.Quantity" />
                        </td>
                        <td>
                                <InputNumber @bind-Value="_editModel.UnitPrice" class="form-control form-control-sm" />
                                <ValidationMessage For="() => _editModel.UnitPrice" />
                        </td>
                        <td>
                                <InputSelect @bind-Value="_editModel.Category" class="form-select form-select-sm">
                                    <option value="">-- Select --</option>
                                    @foreach (var cat in Product.Categories)
                                    {
                                        <option value="@cat">@cat</option>
                                    }
                                </InputSelect>
                                <ValidationMessage For="() => _editModel.Category" />
                        </td>
                        <td>
                                <button type="submit" class="btn btn-success btn-sm me-1">Save</button>
                                <button type="button" class="btn btn-secondary btn-sm" @onclick="CancelEdit">Cancel</button>
                            </EditForm>
                        </td>
                    </tr>
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => StartEdit(product)">Edit</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
}

@code {
    private List<Product>? _products;
    private int? _editingProductId;
    private Product? _editModel;

    protected override async Task OnInitializedAsync()
    {
        _products = await InventoryService.GetAllAsync();
    }

    private void StartEdit(Product product)
    {
        _editingProductId = product.Id;
        _editModel = product.Clone();
    }

    private async Task SaveAsync()
    {
        if (_editModel is null) return;

        await InventoryService.UpdateAsync(_editModel);
        _products = await InventoryService.GetAllAsync();
        _editingProductId = null;
        _editModel = null;
    }

    private void CancelEdit()
    {
        _editingProductId = null;
        _editModel = null;
    }
}

