@page "/inventory"
@rendermode InteractiveServer
@using sv_1b806c2631d24960907d95a717b06975.Models
@using sv_1b806c2631d24960907d95a717b06975.Services
@inject InventoryService InventoryService

<PageTitle>Inventory</PageTitle>

<h1>Inventory</h1>

@if (_products is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped table-bordered">
        <thead class="table-dark">
            <tr>
                <th>Name</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Category</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var product in _products)
            {
                @if (_editingProductId == product.Id && _editModel is not null)
                {
                    <tr>
                        <td>
                            <EditForm Model="_editModel" OnValidSubmit="SaveAsync" FormName="@($"edit-{product.Id}")">
                                <DataAnnotationsValidator />
                                <InputText @bind-Value="_editModel.Name" class="form-control form-control-sm" />
                                <ValidationMessage For="() => _editModel.Name" />
                        </td>
                        <td>
                                <InputNumber @bind-Value="_editModel.Quantity" class="form-control form-control-sm" />
                                <ValidationMessage For="() => _editModel.Quantity" />
                        </td>
                        <td>
                                <InputNumber @bind-Value="_editModel.UnitPrice" class="form-control form-control-sm" />
                                <ValidationMessage For="() => _editModel.UnitPrice" />
                        </td>
                        <td>
                                <InputSelect @bind-Value="_editModel.Category" class="form-select form-select-sm">
                                    <option value="">-- Select --</option>
                                    @foreach (var cat in Product.Categories)
                                    {
                                        <option value="@cat">@cat</option>
                                    }
                                </InputSelect>
                                <ValidationMessage For="() => _editModel.Category" />
                        </td>
                        <td>
                                <button type="submit" class="btn btn-success btn-sm me-1">Save</button>
                                <button type="button" class="btn btn-secondary btn-sm" @onclick="CancelEdit">Cancel</button>
                            </EditForm>
                        </td>
                    </tr>
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => StartEdit(product)">Edit</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
}

@code {
    private List<Product>? _products;
    private int? _editingProductId;
    private Product? _editModel;

    protected override async Task OnInitializedAsync()
    {
        _products = await InventoryService.GetAllAsync();
    }

    private void StartEdit(Product product)
    {
        _editingProductId = product.Id;
        _editModel = product.Clone();
    }

    private async Task SaveAsync()
    {
        if (_editModel is null) return;

        await InventoryService.UpdateAsync(_editModel);
        _products = await InventoryService.GetAllAsync();
        _editingProductId = null;
        _editModel = null;
    }

    private void CancelEdit()
    {
        _editingProductId = null;
        _editModel = null;
    }
}

