        <tbody>
            @foreach (var product in _products)
            {
                @if (_editingProductId == product.Id && _editModel is not null)
                {
                    <tr>
                        <td>
                            <input type="text" class="form-control form-control-sm" @bind="_editModel.Name" />
                            @if (GetError(nameof(Product.Name)) is { } nameErr)
                            {
                                <div class="text-danger small">@nameErr</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control form-control-sm" @bind="_editModel.Quantity" />
                            @if (GetError(nameof(Product.Quantity)) is { } qtyErr)
                            {
                                <div class="text-danger small">@qtyErr</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control form-control-sm" step="0.01" @bind="_editModel.UnitPrice" />
                            @if (GetError(nameof(Product.UnitPrice)) is { } priceErr)
                            {
                                <div class="text-danger small">@priceErr</div>
                            }
                        </td>
                        <td>
                            <select class="form-select form-select-sm" @bind="_editModel.Category">
                                <option value="">-- Select --</option>
                                @foreach (var cat in Product.Categories)
                                {
                                    <option value="@cat">@cat</option>
                                }
                            </select>
                            @if (GetError(nameof(Product.Category)) is { } catErr)
                            {
                                <div class="text-danger small">@catErr</div>
                            }
                        </td>
                        <td>
                            <button type="button" class="btn btn-success btn-sm me-1" @onclick="SaveAsync">Save</button>
                            <button type="button" class="btn btn-secondary btn-sm" @onclick="CancelEdit">Cancel</button>
                        </td>
                    </tr>
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => StartEdit(product)">Edit</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
}

@code {
    private List<Product>? _products;
    private int? _editingProductId;
    private Product? _editModel;
    private Dictionary<string, string> _validationErrors = new();

    protected override async Task OnInitializedAsync()
    {
        _products = await InventoryService.GetAllAsync();
    }

    private void StartEdit(Product product)
    {
        _editingProductId = product.Id;
        _editModel = product.Clone();
        _validationErrors.Clear();
    }

    private bool Validate()
    {
        _validationErrors.Clear();
        if (_editModel is null) return false;

        var context = new ValidationContext(_editModel);
        var results = new List<ValidationResult>();
        if (!Validator.TryValidateObject(_editModel, context, results, validateAllProperties: true))
        {
            foreach (var result in results)
            {
                foreach (var member in result.MemberNames)
                {
                    _validationErrors.TryAdd(member, result.ErrorMessage ?? "Invalid");
                }
            }
            return false;
        }
        return true;
    }

    private string? GetError(string fieldName) =>
        _validationErrors.TryGetValue(fieldName, out var error) ? error : null;

    private async Task SaveAsync()
    {
        if (_editModel is null) return;
        if (!Validate()) return;

        await InventoryService.UpdateAsync(_editModel);
        _products = await InventoryService.GetAllAsync();
        _editingProductId = null;
        _editModel = null;
        _validationErrors.Clear();
    }

    private void CancelEdit()
    {
        _editingProductId = null;
        _editModel = null;
        _validationErrors.Clear();
    }
}

